# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request
from elasticsearch import Elasticsearch

app = Flask(__name__)
es = Elasticsearch()

@app.route('/api/search', methods=['GET'])
def search():
    query = request.args.get('q')

    if not query:
        return {"error": "Missing required parameter 'q'"}, 400

    search_results = es.search(index='your-index-name', body={
        "query": {
            "multi_match" : {
                "query": query,
                "fields": ["product_name", "description"]
            }
        },
        "_source": {"includes": ["id", "product_name", "price"]},
        "size": 10
    })

    results = []
    for hit in search_results['hits']['hits']:
        results.append({
            'id': hit['_id'],
            'product_name': hit['_source']['product_name'],
            'price': hit['_source']['price']
        })

    return {'results': results}, 200

if __name__ == "__main__":
    app.run(port=5000, debug=True)